var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一件重要的事實。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그녀야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"ずっと考えてきた彼女だからこそ、これから向き合う運命に必ず必要な存在であることを。","ENG":"that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.","TWN":"經過長久的思考，你明白在今後即將面對的命運中，她是不可缺少的存在。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"所以你下定決心。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그녀와 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まで彼女とともにいることを。","ENG":"that you'll be with her, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和她一起走到最後。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.","JPN":"意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。","ENG":"Having decided that, you called her to your office. She said she'd be here soon.","TWN":"做好心理準備後，你將她傳喚到老闆辦公室，她說馬上就會過來。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"HANDGUN_ACADEMY_NULL_NULL","text":{"KOREA":"히힛. 아카데미에서 연락 온 줄 알고 조마조마했네요.","JPN":"へへっ。アカデミーからの連絡だと思ってひやひやしてました。","ENG":"Teehee! For a moment, I thought the Academy had contacted you.","TWN":"嘻嘻。我還以為學院發通知給我了，真是讓我有點提心吊膽。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HANDGUN_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"HANDGUN_ACADEMY_NULL_NULL","text":{"KOREA":"딱히 비밀은 아니고 다른 선생님들한테 자주 한소리 듣거든요.","JPN":"別に秘密じゃないですが、他の先生たちによく怒られるんです。","ENG":"This isn't exactly a secret, but the other teachers aren't happy with me.","TWN":"沒什麼秘密，倒是常常被其他老師訓話呢。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HANDGUN_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"HANDGUN_ACADEMY_NULL_NULL","text":{"KOREA":"교육자로서의 자각이 있다면 수업에 충실하라는둥, 서류에 신경 좀 쓰라는둥~","JPN":"教育者として自覚があるなら、もっと授業を充実させろ、書類をちゃんと作成しろ～、とか。","ENG":"They think I'm not a good teacher because I don't pay attention to my class or lecture as much as they do.","TWN":"如果有身為教育者的自覺，就要認真教課、注意相關教育文獻等資訊~"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HANDGUN_ACADEMY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"HANDGUN_ACADEMY_NULL_NULL","text":{"KOREA":"애초에 제가 학생들에게 알려주고 싶은 건 책상과 교탁 사이에서 말로 얻어지는 지식이 아니라고요!","JPN":"そもそも私が生徒たちに教えてあげたいものは、机と教卓を挟んで、言葉で得られる知識じゃないんです！","ENG":"But what I want to teach can't be learned in the classroom or through words.","TWN":"我本來想告訴學生們... 在教室裡不是只有靠語言能力才可以獲得知識。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HANDGUN_ACADEMY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"HANDGUN_ACADEMY_NULL_NULL","text":{"KOREA":"갑자기 무너지는 바닥! 손에 땀을 쥐게 만드는 수수께끼! 침식체들의 습격까지!","JPN":"いきなり崩れる床！手に汗握る謎！侵食体の襲撃まで！","ENG":"What if the ground sinks right under your feet? What if you encounter a mystery? What if a C.O. attacks?","TWN":"突然往下坍塌的地面！讓人捏一把冷汗的謎語！還有侵蝕體的襲擊！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HANDGUN_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"HANDGUN_ACADEMY_NULL_NULL","text":{"KOREA":"살면서 그런 역경을 헤쳐 나가려면 어떤 상황에서도 흔들리지 않는 침착함과 대범한 도전정신을 가르치고 싶은 건데!","JPN":"人生でそういう困難を乗り越えるためには、いかなる状況でも揺るがない強さや大胆なチャレンジ精神を教えたいのに！","ENG":"I want to teach my students how to stay calm, no matter the situation, so they can snatch victory from the jaws of defeat!","TWN":"想教大家在人生中想要克服無數逆境的話，就必須有不輕易動搖的冷靜和大膽的挑戰精神！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HANDGUN_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"HANDGUN_ACADEMY_NULL_NULL","text":{"KOREA":"......그런 건데에~ 히잉~","JPN":"……そのつもりだったのに～はうぅ……","ENG":"Or at least I'm trying... Hnnggg...","TWN":"……就是那樣~ 嗚嗚~"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HANDGUN_ACADEMY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"HANDGUN_ACADEMY_NULL_NULL","text":{"KOREA":"학생들을 유적지로 끌어들이는 건 위험하다면서 매번 다들 견학을 반대하더라고요.","JPN":"生徒たちを遺跡に連れて行くのは危険だと、毎回見学を反対されました。","ENG":"Everyone objects whenever I want to take my students on a field trip to the ruins.","TWN":"每次都說把學生帶到遺跡很危險，一直反對學生們去參觀與觀摩。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HANDGUN_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"HANDGUN_ACADEMY_NULL_NULL","text":{"KOREA":"학생회장에게 물어봤으면 분명 괜찮다고 할 텐데~ 어른이란 사람들이 어쩜 그리 걱정이 많은 건지!","JPN":"生徒会長に聞いてみれば、きっと大丈夫だって言ってくれるはずなのに～。大人たちがビビってどうするんですか！","ENG":"Except the Student President. And she's even younger than those who worry so much!","TWN":"如果問學生會長的話，肯定立即就回答沒關係的~ 這些大人不知道為什麼總是那麼多擔心！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HANDGUN_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"HANDGUN_ACADEMY_NULL_NULL","text":{"KOREA":"......혹시 사장님은 이면세계의 숨겨진 유적지에 관심 없으세요? 제가 1대1로 가이드해드릴게요!","JPN":"……社長は、カウンターサイドの隠された遺跡に興味ありませんか？私がマンツーマンでガイドしますよ！","ENG":"Boss, are you by any chance interested in the hidden ruins on the Counterside? I can be your personal guide.","TWN":"……老闆對異界裡隱藏的遺跡有興趣嗎？我可以專門為你帶路的！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HANDGUN_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"HANDGUN_ACADEMY_NULL_NULL","text":{"KOREA":"배울 의지만 있으면 언제든 오케이! 아카데미 학생이 아니니 오히려 더 좋다고요!","JPN":"学ぶ意志さえあれば、いつでもオッケー！アカデミーの生徒じゃないからむしろいいです！","ENG":"I welcome anyone who wants to learn. You're not with the Academy, which is even better!","TWN":"只要有想要學習的心意跟意願就足夠了！不是學院的學生會更好！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HANDGUN_ACADEMY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"HANDGUN_ACADEMY_NULL_NULL","text":{"KOREA":"사장님은 어른이니까 자기 안전은 스스로 책임지실 수 있겠죠?!","JPN":"社長は大人ですから、自分の安全は自分で守れますよね！？","ENG":"Boss, you're a grownup. You can fend for yourself, right?","TWN":"因為老闆是大人，你可以負責自己的安全吧？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HANDGUN_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"HANDGUN_ACADEMY_NULL_NULL","text":{"KOREA":"자~자~ 이렇게 답답한 시설 안에만 틀어박혀 있는 건 건강에 좋지 않아요! 저랑 같이 신나는 수업을 떠나보자고요! 네?","JPN":"さぁ、さぁ～こんなに息の詰まる施設に閉じこもってると、健康に悪いですよ！私と一緒に楽しい授業に出かけましょう！いいですよね？","ENG":"Come on, staying cooped up inside all day isn't healthy. Let's go on an exciting field trip, shall we?","TWN":"來~ 來~ 一直待在這麼悶的設施裡對健康很不利！和我一起開開心心的上課吧！嗯？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HANDGUN_ACADEMY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"HANDGUN_ACADEMY_NULL_NULL","text":{"KOREA":"그럼 장비 가져올 테니 잠깐만 기다리세요! 어디 딴데 도망가시면 안돼요?!","JPN":"では、装備を持って来ますので、ちょっと待っててください！このまま逃げちゃダメですよ！","ENG":"Good! Then, let me go pick up my gear. Wait here, okay? Don't go anywhere. Promise?","TWN":"那麼我去拿裝備，請等等喔！不要跑掉喔！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HANDGUN_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};